function stabilizeLayerPopup(layer){try{if(!layer||!layer.on)return layer;let anchor=null;const prep=()=>{try{const p=layer.getPopup&&layer.getPopup();if(p&&p.options){p.options.autoPan=false;p.options.keepInView=false;p.options.autoClose=false;p.options.closeOnClick=false}}catch(e){}};const openAnchored=()=>{try{if(mapToolSuppressesObjectPopups())return;if(window._takPinnedPopupLayer&&window._takPinnedPopupLayer!==layer)return;if(!anchor)anchor=layerPopupAnchor(layer);prep();if(layer.openPopup){if(anchor)layer.openPopup(anchor);else layer.openPopup()}setTimeout(()=>{try{clampLeafletPopupToMap(layer.getPopup&&layer.getPopup())}catch(_){ }},0)}catch(e){}};prep();layer.on('mouseover',()=>{if(mapToolSuppressesObjectPopups())return;if(window._takPinnedPopupLayer&&window._takPinnedPopupLayer!==layer)return;if(!layer.isPopupOpen||!layer.isPopupOpen())openAnchored()});layer.on('mouseout',()=>{setTimeout(()=>closeUnpinnedPopup(layer),120)});layer.on('click',ev=>{try{if(mapToolSuppressesObjectPopups())return;if(window._takPinnedPopupLayer&&window._takPinnedPopupLayer!==layer){const old=window._takPinnedPopupLayer;old._takPopupPinned=false;if(old.closePopup)old.closePopup()}layer._takPopupPinned=true;window._takPinnedPopupLayer=layer;openAnchored();if(ev&&ev.originalEvent)L.DomEvent.stop(ev.originalEvent)}catch(e){}});layer.on('popupopen',e=>{try{if(mapToolSuppressesObjectPopups()&&!layer._takPopupPinned){if(layer.closePopup)layer.closePopup();return}const p=e.popup;prep();if(!anchor)anchor=layerPopupAnchor(layer);if(p&&anchor&&p.setLatLng)p.setLatLng(anchor);setTimeout(()=>clampLeafletPopupToMap(p),0);const el=p&&p.getElement&&p.getElement();if(!el)return;el.addEventListener('mouseenter',()=>{layer._takPopupHover=true});el.addEventListener('mouseleave',()=>{layer._takPopupHover=false;setTimeout(()=>{if(!layer._takPopupHover)closeUnpinnedPopup(layer)},180)});el.addEventListener('click',ev=>ev.stopPropagation());}catch(x){}})}catch(e){}return layer}
