function ensureMeasurePopupDock(){let el=document.getElementById('measurePopupDock');if(el)return el;el=document.createElement('div');el.id='measurePopupDock';el.className='measure-popup-dock';el.style.display='none';document.body.appendChild(el);let drag=null;el.addEventListener('pointerdown',ev=>{if(ev.target&&String(ev.target.tagName||'').toLowerCase()==='button')return;drag={x:ev.clientX,y:ev.clientY,left:el.getBoundingClientRect().left,top:el.getBoundingClientRect().top};try{el.setPointerCapture(ev.pointerId)}catch(_){ }ev.preventDefault()});el.addEventListener('pointermove',ev=>{if(!drag)return;const r=map&&map.getContainer?map.getContainer().getBoundingClientRect():{left:0,top:86,right:innerWidth,bottom:innerHeight};const nx=Math.max(r.left+4,Math.min(r.right-80,drag.left+ev.clientX-drag.x));const ny=Math.max(r.top+4,Math.min(r.bottom-50,drag.top+ev.clientY-drag.y));el.dataset.moved='1';el.style.left=nx+'px';el.style.top=ny+'px';el.style.right='auto';el.style.bottom='auto'});el.addEventListener('pointerup',()=>{drag=null});el.addEventListener('pointercancel',()=>{drag=null});return el}
