  window.v233DrawMapClick=function(ll){const st=v233DrawState;if(['rectangle','square','circle','ellipse'].includes(st.mode)){st.points.push(ll);if(st.points.length>=2)v233FinishDraw();return}st.points.push(ll);v233RedrawDrawTemp()};function v233RedrawDrawTemp(){const st=v233DrawState;v233ClearTemp(st);if(st.points.length<1)return;st.layer=(st.points.length===1?L.marker(st.points[0]):L.polyline(st.points,{color:st.color||'#ff6f2e',weight:3,dashArray:st.mode==='freehand'?'4 5':''})).addTo(map)}window.v233UndoDraw=function(){v233DrawState.points.pop();v233RedrawDrawTemp()};window.v233ClearDraw=function(){v233DrawState.points=[];v233ClearTemp(v233DrawState)};
