  function readViewshedFields(changedId){try{const v=activeVs();const lat=Number(field('viewshedLat').value),lon=Number(field('viewshedLon').value);v.lat=Number.isFinite(lat)?lat:null;v.lon=Number.isFinite(lon)?lon:null;const oldRadius=v.radius,oldUnit=v.radiusUnit;v.height=clamp(field('viewshedHeight').value,0,100000,6);v.heightUnit=field('viewshedHeightUnit').value||'ft';v.radius=clamp(field('viewshedRadius').value,0.01,99999,2);v.radiusUnit=field('viewshedRadiusUnit').value||'mi';if(changedId==='viewshedQuality'){v.quality=field('viewshedQuality').value||'High';v.qualityManual=true}else if(!v.qualityManual&&(changedId==='viewshedRadius'||changedId==='viewshedRadiusUnit'||oldRadius!==v.radius||oldUnit!==v.radiusUnit)){v.quality=autoViewshedQuality(v.radius,v.radiusUnit);if(field('viewshedQuality'))field('viewshedQuality').value=v.quality}else{v.quality=v.quality||autoViewshedQuality(v.radius,v.radiusUnit);if(field('viewshedQuality'))field('viewshedQuality').value=v.quality}v.visibleColor=field('viewshedVisibleColor').value||'#46d16c';v.blockedColor=field('viewshedBlockedColor').value||'#ef514d';v.visibleOpacity=clamp(field('viewshedVisibleOpacity').value,0,100,68)/100;v.blockedOpacity=clamp(field('viewshedBlockedOpacity').value,0,100,44)/100;if(field('viewshedElevationSource'))v.elevationSource=field('viewshedElevationSource').value||'Auto';if(field('viewshedAcceleration'))v.acceleration=field('viewshedAcceleration').value||'Auto';if(field('viewshedCacheElevation'))v.cacheElevation=!!field('viewshedCacheElevation').checked;return v}catch(_){return activeVs()}}
