  function findNearestPoint(ll){let best=null,bestD=Infinity;const groups=[(typeof takMarkerLayer!=='undefined'?takMarkerLayer:window.takMarkerLayer),(typeof dataSyncLayer!=='undefined'?dataSyncLayer:window.dataSyncLayer),(typeof importedLayer!=='undefined'?importedLayer:window.importedLayer)];groups.forEach(g=>{try{g&&g.eachLayer&&g.eachLayer(l=>{try{let p=null;if(l.getLatLng)p=l.getLatLng();else return;const d=map.latLngToContainerPoint(ll).distanceTo(map.latLngToContainerPoint(p));if(d<bestD){bestD=d;best=p}}catch(_){}})}catch(_){}});return bestD<=30?best:null}
  function unitMeters(v,u){v=Number(v)||0;if(u==='ft')return v*0.3048;if(u==='mi')return v*1609.344;if(u==='km')return v*1000;return v}
