  async function sampleElevationsEsri(points,opts){opts=opts||{};const st=window.v249Viewshed;try{if(typeof loadCesiumAssets==='function'&&typeof cesiumTerrainProvider==='function'){await loadCesiumAssets();if(!window.Cesium)return {ok:false,source:'Esri World Elevation 3D unavailable',elev:null};if(!st.terrainProvider)st.terrainProvider=await cesiumTerrainProvider();const pointCount=viewshedPointCount(points);const out=new Array(pointCount);const chunk=4000;const useMost=!!Cesium.sampleTerrainMostDetailed;const source=useMost?'Esri World Elevation 3D high-res terrain':'Esri World Elevation 3D coarse terrain';let min=Infinity,max=-Infinity,valid=0;for(let i=0;i<pointCount;i+=chunk){const slice=viewshedPointSlice(points,i,i+chunk);const cart=slice.map(p=>Cesium.Cartographic.fromDegrees(p.lng,p.lat));const terrainPromise=useMost?Cesium.sampleTerrainMostDetailed(st.terrainProvider,cart):Cesium.sampleTerrain(st.terrainProvider,11,cart);const sampled=await viewshedTimeout(terrainPromise,45000,'Esri terrain sample');for(let j=0;j<sampled.length;j++){const h=Number(sampled[j].height);const val=Number.isFinite(h)?h:0;out[i+j]=val;if(Number.isFinite(h)){valid++;if(val<min)min=val;if(val>max)max=val}}if(field('viewshedStatus')){const pct=Math.min(99,Math.round(((i+sampled.length)/pointCount)*100));field('viewshedStatus').textContent='Sampling elevation ('+source+')... '+pct+'%'}await new Promise(r=>setTimeout(r,0))}const spread=(valid>1&&Number.isFinite(min)&&Number.isFinite(max))?(max-min):0;return {ok:valid>0,cached:false,source:source+(spread<0.5?' · flat/low variation':''),elev:out,valid,spread}}}catch(e){console.warn('Esri viewshed terrain sample unavailable',e)}return {ok:false,source:'Esri World Elevation 3D unavailable',elev:null}}
