  const LOCAL_ELEV_DB='takmapLocalElevationV1';
  function localElevState(){window.takLocalElevation=window.takLocalElevation||{loaded:false,loading:null,tiles:new Map(),meta:[]};return window.takLocalElevation}
  function localElevKey(lat0,lon0,size){return 'hgt|'+lat0+'|'+lon0+'|'+size}
  function localElevTileId(lat0,lon0){return 'hgt|'+Math.floor(lat0)+'|'+Math.floor(lon0)}
  function openLocalElevDb(){return new Promise((resolve,reject)=>{try{const req=indexedDB.open(LOCAL_ELEV_DB,1);req.onupgradeneeded=e=>{const db=e.target.result;if(!db.objectStoreNames.contains('tiles'))db.createObjectStore('tiles',{keyPath:'id'});if(!db.objectStoreNames.contains('meta'))db.createObjectStore('meta',{keyPath:'id'})};req.onsuccess=()=>resolve(req.result);req.onerror=()=>reject(req.error||new Error('IndexedDB open failed'))}catch(e){reject(e)}})}
