  async function loadLocalElevationTiles(){const st=localElevState();if(st.loaded)return st;if(st.loading)return st.loading;st.loading=(async()=>{try{const db=await openLocalElevDb();await new Promise((resolve,reject)=>{const tx=db.transaction(['tiles'],'readonly');const req=tx.objectStore('tiles').openCursor();req.onsuccess=e=>{const cur=e.target.result;if(cur){const tile=cur.value;if(tile&&tile.id){st.tiles.set(tile.id,tile);st.tiles.set(localElevTileId(tile.lat0,tile.lon0),tile);};cur.continue()}else resolve()};req.onerror=()=>reject(req.error||new Error('IndexedDB cursor failed'));tx.oncomplete=()=>{try{db.close()}catch(_){}}});st.meta=[...st.tiles.values()].filter((v,i,a)=>a.findIndex(x=>x.id===v.id)===i).map(t=>({id:t.id,name:t.name,type:t.type,lat0:t.lat0,lon0:t.lon0,size:t.size}));st.loaded=true;updateLocalElevationUi();return st}catch(e){console.warn('local elevation load failed',e);st.loaded=true;updateLocalElevationUi('Local elevation load failed: '+String(e&&e.message||e));return st}})();return st.loading}
