  function sampleHgtTile(tile,lat,lng){try{if(!tile)return null;const size=Number(tile.size);if(!(size>1))return null;const lat0=Number(tile.lat0),lon0=Number(tile.lon0);if(lat<lat0||lat>lat0+1||lng<lon0||lng>lon0+1)return null;const vals=new Int16Array(tile.buffer);const col=(lng-lon0)*(size-1);const row=(lat0+1-lat)*(size-1);let c0=Math.floor(col),r0=Math.floor(row);let c1=Math.min(size-1,c0+1),r1=Math.min(size-1,r0+1);c0=Math.max(0,Math.min(size-1,c0));r0=Math.max(0,Math.min(size-1,r0));const tx=col-c0,ty=row-r0;function v(r,c){const n=vals[r*size+c];return n<=-32768?NaN:Number(n)}const v00=v(r0,c0),v10=v(r0,c1),v01=v(r1,c0),v11=v(r1,c1);const arr=[v00,v10,v01,v11].filter(Number.isFinite);if(!arr.length)return null;if(arr.length<4)return arr.reduce((a,b)=>a+b,0)/arr.length;const a=v00*(1-tx)+v10*tx,b=v01*(1-tx)+v11*tx;return a*(1-ty)+b*ty}catch(_){return null}}
