    const half=n/2;
    const maxPts=Math.ceil(Math.PI*n*n/4)+8;
    let latArr=new Float64Array(maxPts);
    let lngArr=new Float64Array(maxPts);
    let pixArr=new Int32Array(Math.max(2,(maxPts-1)*2));
