    const nw=viewshedGridLatLngMain(center,-radiusM,radiusM), se=viewshedGridLatLngMain(center,radiusM,-radiusM);
    const minLat=Math.min(nw.lat,se.lat), maxLat=Math.max(nw.lat,se.lat), minLng=Math.min(nw.lng,se.lng), maxLng=Math.max(nw.lng,se.lng);
