  function makeTileMesh(Cesium,tile,idx,grid){const b=tileBounds(tile);if(!b)return null;const pos=[];const indices=[];let valid=0,min=Infinity,max=-Infinity;for(let r=0;r<grid;r++){const lat=b.north-(b.north-b.south)*(r/(grid-1));for(let c=0;c<grid;c++){const lon=b.west+(b.east-b.west)*(c/(grid-1));let h=sampleLocal(lat,lon);if(!Number.isFinite(h))h=0;else{valid++;if(h<min)min=h;if(h>max)max=h}const cart=Cesium.Cartesian3.fromDegrees(lon,lat,h);pos.push(cart.x,cart.y,cart.z)}}for(let r=0;r<grid-1;r++){for(let c=0;c<grid-1;c++){const i=r*grid+c;indices.push(i,i+1,i+grid,i+1,i+grid+1,i+grid)}}if(!valid)return null;const values=new Float64Array(pos);const ind=(values.length/3>65535)?new Uint32Array(indices):new Uint16Array(indices);const geom=new Cesium.Geometry({attributes:{position:new Cesium.GeometryAttribute({componentDatatype:Cesium.ComponentDatatype.DOUBLE,componentsPerAttribute:3,values:values})},indices:ind,primitiveType:Cesium.PrimitiveType.TRIANGLES,boundingSphere:Cesium.BoundingSphere.fromVertices(values)});const color=(Cesium.Color&&Cesium.Color.fromCssColorString?Cesium.Color.fromCssColorString('#ff6f2e').withAlpha(.32):undefined);const inst=new Cesium.GeometryInstance({geometry:geom,attributes:color?{color:Cesium.ColorGeometryInstanceAttribute.fromColor(color)}:{},id:'local-dem-mesh-v320-'+String(tile.id||idx)});const prim=new Cesium.Primitive({geometryInstances:inst,appearance:new Cesium.PerInstanceColorAppearance({flat:false,translucent:true,closed:false}),asynchronous:false});prim._takLocalDemMesh=true;prim._takValid=valid;prim._takMin=min;prim._takMax=max;return prim}
