  async function fetchCategory(cat){if(cat.local)return state.cache[cat.id]||{id:cat.id,records:[]};const url='/api/tak-map/satellite/celestrak?group='+encodeURIComponent(cat.group);let j=null;try{const r=await fetch(url,{cache:'no-store'});j=await r.json();if(!r.ok||!j.ok)throw new Error((j&&j.error)||('HTTP '+r.status))}catch(e){const direct='https://celestrak.org/NORAD/elements/gp.php?GROUP='+encodeURIComponent(cat.group)+'&FORMAT=json';const r=await fetch(direct,{cache:'no-store'});j={ok:r.ok,records:await r.json()};if(!r.ok)throw new Error('CelesTrak HTTP '+r.status)}const rows=(Array.isArray(j.records)?j.records:[]).map(function(r){return normRec(r,cat)});const entry={id:cat.id,label:cat.label,group:cat.group,source:'CelesTrak GP JSON',updatedAt:Date.now(),records:rows};await dbPut(entry);state.cache[cat.id]=entry;return entry}
