function renderAt(ms,force){ms=Math.max(replay.startMs,Math.min(replay.endMs,Number(ms)||replay.startMs));rebuildTo(ms);replay.currentMs=ms;if(replay.followUid){const e=replay.latest.get(replay.followUid);if(e)replay.map.panTo([e.lat,e.lon],{animate:false});else replay.followUid=''}const now=performance.now();if(force||now-replay.lastUiAt>=180){replay.lastUiAt=now;const pct=replay.endMs>replay.startMs?Math.round((ms-replay.startMs)*1000/(replay.endMs-replay.startMs)):0;$('replayTimelineV415').value=String(pct);const pf=$('replayPlaybackFillV433');if(pf)pf.style.width=(pct/10)+'%';$('replayNowV415').textContent=new Date(ms).toLocaleTimeString();$('replayVisibleV415').textContent=replay.latest.size+' visible';updateCounts()}if(ms>=replay.endMs)pause()}
function seekTo(ms){renderAt(ms,true);if(replay.playing){replay.playAnchorReplay=replay.currentMs;replay.playAnchorReal=performance.now()}}
function appendTrackState(e){const t=replay.tracked.get(e.uid);if(!t||e.displayMs<t.startedMs)return;if(t.segmentId!==e.segmentId){if(t.line){try{replay.trailLayer.removeLayer(t.line)}catch(_){}}t.segmentId=e.segmentId;t.line=null;t.points=[];t.lastSampleMs=NaN}const sampleGap=Math.max(500,replay.speed*250);if(Number.isFinite(t.lastSampleMs)&&e.displayMs-t.lastSampleMs<sampleGap)return;t.lastSampleMs=e.displayMs;const point=[e.lat,e.lon],last=t.points[t.points.length-1];if(!last||Math.abs(last[0]-point[0])>1e-8||Math.abs(last[1]-point[1])>1e-8)t.points.push(point);if(t.points.length>5000)t.points.splice(0,t.points.length-5000);if(t.points.length>1){if(!t.line)t.line=L.polyline(t.points,{color:'#a979ff',weight:3,opacity:.9}).addTo(replay.trailLayer);else t.line.setLatLngs(t.points)}}
function appendTrack(e){appendTrackState(Object.assign({},e,{displayMs:replay.currentMs}))}
function toggleTrack(uid){if(replay.tracked.has(uid)){replay.tracked.delete(uid)}else{const e=replay.latest.get(uid);replay.tracked.set(uid,{startedMs:replay.currentMs,lastSampleMs:replay.currentMs,segmentId:e?.segmentId,points:e?[[e.lat,e.lon]]:[],line:null})}renderAt(replay.currentMs,true);updateCounts()}
function clearTrail(uid){const t=replay.tracked.get(uid);if(t?.line){try{replay.trailLayer.removeLayer(t.line)}catch(_){}t.line=null;t.points=[]}}
function toggleFollow(uid){replay.followUid=replay.followUid===uid?'':uid;updateCounts()}
function updateCounts(){$('replayTrackedV415')&&($('replayTrackedV415').textContent=String(replay.tracked.size));$('replayFollowedV415')&&($('replayFollowedV415').textContent=replay.followUid?(replay.latest.get(replay.followUid)?.callsign||replay.followUid):'None')}
function togglePlay(){replay.playing?pause():play()}
function replayFrame(now){if(!replay.playing)return;const target=replay.playAnchorReplay+(now-replay.playAnchorReal)*replay.speed;if(!replay.loadComplete&&target>=replay.loadedUntilMs-1000){renderAt(Math.max(replay.startMs,replay.loadedUntilMs-1000),true);replay.buffering=true;replay.resumeAfterBuffer=true;pause(true);updateBufferUi();return}renderAt(target,false);if(replay.playing)replay.raf=requestAnimationFrame(replayFrame)}
function play(){if(!replay.events.length||replay.playing)return;if(!replay.loadComplete&&replay.loadedUntilMs-replay.currentMs<2000){replay.buffering=true;replay.resumeAfterBuffer=true;updateBufferUi();return}replay.buffering=false;replay.resumeAfterBuffer=false;updateBufferUi();replay.playing=true;setReplayPlayIcon(false);replay.playAnchorReal=performance.now();replay.playAnchorReplay=replay.currentMs;if(w.requestAnimationFrame)replay.raf=requestAnimationFrame(replayFrame);else replay.timer=setInterval(()=>{const t=replay.playAnchorReplay+(performance.now()-replay.playAnchorReal)*replay.speed;if(!replay.loadComplete&&t>=replay.loadedUntilMs-1000){replay.buffering=true;replay.resumeAfterBuffer=true;pause(true);updateBufferUi()}else renderAt(t,false)},100)}
function pause(forBuffer){replay.playing=false;if(replay.raf){cancelAnimationFrame(replay.raf);replay.raf=null}clearInterval(replay.timer);replay.timer=null;replay.lastFrameAt=0;if(!forBuffer){replay.resumeAfterBuffer=false;replay.buffering=false;updateBufferUi()}setReplayPlayIcon(true)}
d.addEventListener('visibilitychange',()=>{if(!replay.playing)return;const now=performance.now();replay.currentMs=replay.playAnchorReplay+(now-replay.playAnchorReal)*replay.speed;replay.playAnchorReplay=replay.currentMs;replay.playAnchorReal=now});
function setVersion(){installVersionGuardV442();enforceVersionUiV442();installReliefRailV442();installOfflineSteppersV442()}
function boot(){setVersion();createUi();installUiV442();installReplayBannerLayoutV441();positionReplayBannerV441();installFetchPause();api('/api/tak-map/replay/config').then(j=>setStatus(j.configured?'Replay API configured':'Replay API certificate not configured',!!j.configured)).catch(e=>setStatus(e.message,false))}
if(d.readyState==='loading')d.addEventListener('DOMContentLoaded',()=>setTimeout(boot,180),{once:true});else setTimeout(boot,180);[700,1600,3200].forEach(ms=>setTimeout(()=>{createUi();setVersion()},ms));
